# auto-generated by RADVD service (utility.py)

interface eth0 {
        AdvSendAdvert on;
        MinRtrAdvInterval 3;
        MaxRtrAdvInterval 10;

    prefix 2001::/64 {
        AdvOnLink on;
        AdvAutonomous on;
    };

    prefix fd00::/64 {
        AdvOnLink on;
        AdvAutonomous on;
    };
};

#!/bin/sh # auto-generated by StaticRoute service (utility.py) # NOTE: this service must be customized to be of any use # Below are samples that you can uncomment and edit.
ip -6 addr add 2001:0:0:0::1/64 dev eth0 ip -6 addr add FD00:0:0:0::1/64 dev eth0 ip -6 addr add 2001:0:0:FF::B/127 dev eth1 ip -6 addr add FD00:0:0:FF::B/127 dev eth1
ip -6 route add default via 2001:0:0:FF::A dev eth1

